/**
 * Watchout Timeline Discovery — Node-RED Function Node
 *
 * Trigger this node by wiring an "inject" or dashboard ui_button node to it.
 * It fetches timelines from Watchout, compares them to the stored mapping,
 * stores the pending diff in flow context, and outputs a message suitable
 * for displaying the diff in a UI template node.
 *
 * Flow context variables used:
 *   flow.get('watchout_config')   — { host, port, storageFile }
 *   flow.get('watchout_mapping')  — { [contentId]: timelineId }
 *   flow.get('watchout_pending')  — pending new mapping (awaiting confirmation)
 *
 * Output msg.payload:
 *   {
 *     status:     'diff_ready' | 'no_changes' | 'error',
 *     hasChanges: boolean,
 *     diff:       { added: [], removed: [], unchanged: [], changed: [] },
 *     newMapping: { [contentId]: timelineId },
 *     diffLines:  string[],   // human-readable lines for display
 *     error:      string      // only on status === 'error'
 *   }
 */

'use strict';

const http = require('http');

// ─── Config ────────────────────────────────────────────────────────────────

const cfg = flow.get('watchout_config') || {};
const host = cfg.host || 'localhost';
const port = cfg.port || 3019;
const REQUEST_TIMEOUT_MS = 10000;

// ─── Helpers ───────────────────────────────────────────────────────────────

function httpGet(path) {
    return new Promise((resolve, reject) => {
        const options = {
            hostname: host,
            port: port,
            path: path,
            method: 'GET',
            headers: { 'Content-Type': 'application/json' },
        };
        const req = http.request(options, (res) => {
            let data = '';
            res.on('data', (chunk) => { data += chunk; });
            res.on('end', () => {
                try {
                    resolve({ statusCode: res.statusCode, body: JSON.parse(data) });
                } catch (e) {
                    resolve({ statusCode: res.statusCode, body: data });
                }
            });
            res.on('error', reject);
        });
        req.on('error', reject);
        req.setTimeout(REQUEST_TIMEOUT_MS, () => req.destroy(new Error('Request timed out')));
        req.end();
    });
}

function parseTimelineName(name) {
    if (!name || name.startsWith('_')) return null;
    return name.trim().toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, '');
}

function compareMapping(oldMap, newMap) {
    const oldKeys = Object.keys(oldMap);
    const newKeys = Object.keys(newMap);
    return {
        removed:   oldKeys.filter(k => !(k in newMap)),
        added:     newKeys.filter(k => !(k in oldMap)),
        unchanged: oldKeys.filter(k => (k in newMap) && oldMap[k] === newMap[k]),
        changed:   oldKeys.filter(k => (k in newMap) && oldMap[k] !== newMap[k]),
    };
}

function formatDiff(diff) {
    const lines = [];
    diff.removed.forEach(n   => lines.push(`❌ Removed  : Timeline '${n}' no longer exists`));
    diff.added.forEach(n     => lines.push(`✨ Added    : New timeline '${n}' discovered`));
    diff.changed.forEach(n   => lines.push(`🔄 Changed  : Timeline '${n}' ID has changed`));
    diff.unchanged.forEach(n => lines.push(`✓  Unchanged: '${n}'`));
    return lines;
}

// ─── Main ──────────────────────────────────────────────────────────────────

async function discover() {
    let result;
    try {
        result = await httpGet('/v0/timelines');
    } catch (err) {
        return { status: 'error', error: `Connection failed: ${err.message}` };
    }

    if (result.statusCode !== 200) {
        return { status: 'error', error: `Watchout returned HTTP ${result.statusCode}` };
    }

    const timelines = Array.isArray(result.body) ? result.body : [];

    // Build new mapping
    const newMapping = {};
    timelines.forEach(tl => {
        const contentId = parseTimelineName(tl.name);
        if (contentId) {
            newMapping[contentId] = String(tl.id);
        }
    });

    // Compare with stored mapping
    const storedMapping = flow.get('watchout_mapping') || {};
    const diff = compareMapping(storedMapping, newMapping);
    const hasChanges = diff.added.length > 0 || diff.removed.length > 0 || diff.changed.length > 0;

    // Store pending mapping (not saved until confirmed)
    flow.set('watchout_pending', newMapping);

    return {
        status:     hasChanges ? 'diff_ready' : 'no_changes',
        hasChanges,
        diff,
        newMapping,
        diffLines:  formatDiff(diff),
    };
}

// Execute and pass result downstream
discover().then(payload => {
    node.send({ payload, topic: 'watchout/discovery' });
}).catch(err => {
    node.send({ payload: { status: 'error', error: err.message }, topic: 'watchout/discovery' });
});

return null; // async — result sent in promise callback

/**
 * Watchout Discovery Confirm — Node-RED Function Node
 *
 * Wire this node from a dashboard [Confirm & Save] button or HTTP endpoint.
 * It takes the pending mapping stored by the discovery node and persists it
 * to both flow context and the file system.
 *
 * Flow context variables used:
 *   flow.get('watchout_pending')  — the new mapping to confirm
 *   flow.set('watchout_mapping')  — updated with confirmed mapping
 *   flow.get('watchout_config')   — { storageFile } (optional path override)
 *
 * Output msg.payload:
 *   { status: 'saved' | 'nothing_pending' | 'error', mapping: {}, savedAt: string }
 */

'use strict';

const fs   = require('fs');
const path = require('path');

const pending = flow.get('watchout_pending');

if (!pending) {
    node.send({ payload: { status: 'nothing_pending' }, topic: 'watchout/confirm' });
    return null;
}

// Persist to flow context
flow.set('watchout_mapping', pending);
flow.set('watchout_pending', null);

// Persist to file
const cfg         = flow.get('watchout_config') || {};
const storageFile = cfg.storageFile || path.join(__dirname, '../data/timeline-mapping.json');

try {
    const dir = path.dirname(storageFile);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    const data = { mapping: pending, lastSaved: new Date().toISOString() };
    fs.writeFileSync(storageFile, JSON.stringify(data, null, 2));
    node.log('[WatchoutHTTP] Timeline mapping saved to ' + storageFile);
} catch (err) {
    node.warn('[WatchoutHTTP] Could not save mapping to file: ' + err.message);
    node.send({ payload: { status: 'error', error: err.message }, topic: 'watchout/confirm' });
    return null;
}

const savedAt = new Date().toISOString();
node.send({
    payload: { status: 'saved', mapping: pending, savedAt },
    topic:   'watchout/confirm',
});

return null;

/**
 * Watchout Discovery Cancel — Node-RED Function Node
 *
 * Wire this node from a dashboard [Cancel] button.
 * Clears the pending mapping without saving anything.
 *
 * Flow context variables modified:
 *   flow.set('watchout_pending', null)
 *
 * Output msg.payload:
 *   { status: 'cancelled' }
 */

'use strict';

flow.set('watchout_pending', null);

node.send({ payload: { status: 'cancelled' }, topic: 'watchout/cancel' });

return null;

/**
 * Watchout Timeline Control — Node-RED Function Node
 *
 * Accepts an incoming message with a command and executes it against Watchout.
 *
 * Input msg.payload:
 *   {
 *     command:   'start' | 'stop' | 'pause' | 'setVar' | 'getState',
 *     contentId: string,    // for start / stop / pause  (looked up in mapping)
 *     varName:   string,    // for setVar
 *     varValue:  any,       // for setVar
 *   }
 *
 * Output msg.payload:
 *   {
 *     success:    boolean,
 *     command:    string,
 *     timelineId: string,   // resolved timeline ID (start / stop / pause)
 *     statusCode: number,
 *     body:       any,
 *     error:      string    // only on failure
 *   }
 *
 * Flow context variables used:
 *   flow.get('watchout_config')   — { host, port }
 *   flow.get('watchout_mapping')  — { [contentId]: timelineId }
 */

'use strict';

const http = require('http');

// ─── Config ────────────────────────────────────────────────────────────────

const cfg = flow.get('watchout_config') || {};
const host = cfg.host || 'localhost';
const port = cfg.port || 3019;
const REQUEST_TIMEOUT_MS = 10000;

// ─── Helpers ───────────────────────────────────────────────────────────────

function httpRequest(method, urlPath, body) {
    return new Promise((resolve, reject) => {
        const options = {
            hostname: host,
            port: port,
            path: urlPath,
            method: method,
            headers: { 'Content-Type': 'application/json' },
        };
        const req = http.request(options, (res) => {
            let data = '';
            res.on('data', (chunk) => { data += chunk; });
            res.on('end', () => {
                try {
                    resolve({ statusCode: res.statusCode, body: JSON.parse(data) });
                } catch (e) {
                    resolve({ statusCode: res.statusCode, body: data });
                }
            });
            res.on('error', reject);
        });
        req.on('error', reject);
        req.setTimeout(REQUEST_TIMEOUT_MS, () => req.destroy(new Error('Request timed out')));
        if (body !== undefined) req.write(JSON.stringify(body));
        req.end();
    });
}

function resolveTimelineId(contentId) {
    const mapping = flow.get('watchout_mapping') || {};
    if (contentId in mapping) return mapping[contentId];
    return String(contentId); // assume it is already a raw timeline ID
}

// ─── Main ──────────────────────────────────────────────────────────────────

const input = msg.payload || {};
const command = input.command;

async function execute() {
    let timelineId;

    switch (command) {
        case 'start': {
            timelineId = resolveTimelineId(input.contentId);
            const r = await httpRequest('POST', `/v0/timelines/${timelineId}/play`);
            return { success: r.statusCode < 300, command, timelineId, statusCode: r.statusCode, body: r.body };
        }
        case 'stop': {
            timelineId = resolveTimelineId(input.contentId);
            const r = await httpRequest('POST', `/v0/timelines/${timelineId}/stop`);
            return { success: r.statusCode < 300, command, timelineId, statusCode: r.statusCode, body: r.body };
        }
        case 'pause': {
            timelineId = resolveTimelineId(input.contentId);
            const r = await httpRequest('POST', `/v0/timelines/${timelineId}/pause`);
            return { success: r.statusCode < 300, command, timelineId, statusCode: r.statusCode, body: r.body };
        }
        case 'setVar': {
            const r = await httpRequest('PUT', `/v0/vars/${encodeURIComponent(input.varName)}`, { value: input.varValue });
            return { success: r.statusCode < 300, command, statusCode: r.statusCode, body: r.body };
        }
        case 'getState': {
            const r = await httpRequest('GET', '/v0/state');
            return { success: r.statusCode < 300, command, statusCode: r.statusCode, body: r.body };
        }
        default:
            throw new Error(`Unknown command: '${command}'`);
    }
}

execute().then(payload => {
    node.send({ payload, topic: `watchout/${command}` });
}).catch(err => {
    node.send({ payload: { success: false, command, error: err.message }, topic: `watchout/${command}` });
});

return null; // async

